mapper.select:
select p.*,s.company_name from products p join sellers s ON p.seller_id = s.seller_id where p.status = 'APPROVED'
AND (p.category_id=#{category_id} OR p.category_id IN (
    select category_id from categories where parent_id = #{category_id})
)
ORDER BY p.product_id DESC
LIMIT #{start}, #{blockList}

select COUNT(*)
from products
where status = 'APPROVED'
  AND (
        category_id = #{category_id}
        OR category_id IN (
            select category_id
            from categories
            where parent_id = #{category_id}
        )
  )

select p.*,s.company_name from products p JOIN sellers s ON p.seller_id = s.seller_id
where p.status = 'APPROVED' AND p.sale_price > 0
ORDER BY p.sale_price_updated_at DESC, p.product_id DESC LIMIT #{start}, #{blockList}
